import util,{parseArgs}from"node:util";import picocolors from"picocolors";const{values:values}=parseArgs({strict:!1,options:{debug:{type:"boolean"}}}),IS_DEBUG_ENABLED=values.debug??!1,IS_COLORS=!process.env.NO_COLOR,noop=()=>{},inspectOptions={maxArrayLength:null,depth:null,colors:IS_COLORS};export const inspect=o=>console.log(util.inspect(o,inspectOptions));const ctx=o=>"string"==typeof o?picocolors.yellow(`[${o}]`):`${picocolors.yellow(`[${o[0]}]`)} ${picocolors.cyan(o[1])}`,logArray=o=>{console.log(util.inspect(o.sort(),inspectOptions))};export const debugLog=IS_DEBUG_ENABLED?(o,t)=>console.log(`${ctx(o)} ${t}`):noop;export const debugLogObject=IS_DEBUG_ENABLED?(o,t,s)=>{console.log(`${ctx(o)} ${t}`),console.log(util.inspect("function"==typeof s?s():s,inspectOptions))}:noop;export const debugLogArray=IS_DEBUG_ENABLED?(o,t,s)=>{const e=Array.from("function"==typeof s?s():s);console.debug(`${ctx(o)} ${t} (${e.length})`),logArray(e)}:noop;